#include <iostream>
#include <fstream>
#include <string>
#include <sstream>
#include <algorithm> // for std::transform

using namespace std;

int main() {
    string filename, targetWord;
    int count = 0;

    // Get filename and target word from the user
    cout << "Enter filename: ";
    cin >> filename;
    cout << "Enter word to count: ";
    cin >> targetWord;

    // Case-insensitive counting (optional but recommended)
    transform(targetWord.begin(), targetWord.end(), targetWord.begin(), ::tolower); 

    ifstream file(filename);
    string line;

    if (file.is_open()) {
        while (getline(file, line)) {
            // Tokenize the line into words
            stringstream ss(line);
            string word;
            while (ss >> word) {
                transform(word.begin(), word.end(), word.begin(), ::tolower); // Case-insensitive comparison
                if (word == targetWord) {
                    count++;
                }
            }
        }
        file.close();
        cout << "Word '" << targetWord << "' appears " << count << " times in the file." << endl;
    } else {
        cerr << "Unable to open file: " << filename << endl;
        return 1; // Indicate an error
    }

    return 0;
}
